        values_flat = torch.empty((topk_batch,), device=inp.device, dtype=inp.dtype)
        indices_flat = torch.empty((topk_batch,), device=inp.device, dtype=torch.int64)
        inp_2d = inp.reshape(topk_batch, dim_size)
        block_n = triton.next_power_of_2(dim_size)
