        # tie ordering matches the CPU reference. Split large batches so
        # Cambricon's 16-bit grid dimension limit is not exceeded.
        use_wide_topk = k > math.log2(dim_size)
        topk_k = (
            min(dim_size, max(k, int(math.log2(dim_size)) + 2)) if use_wide_topk else k
        )
        if use_wide_topk and topk_batch > TOTAL_CORE_NUM:
            inp_2d = inp.reshape(topk_batch, dim_size)
            values_2d = torch.empty(
                (topk_batch, topk_k), device=inp.device, dtype=inp.dtype
            )
